                                    <label class=\\\"control-label\\\"\\r\\n                                                >Fecha de Emisión</label\\r\\n                                            >\\r\\n                                            <el-date-picker\\r\\n                                                style=\\\"width:100%;\\\"\\r\\n                                                v-model=\\\"form.date_of_issue\\\"\\r\\n                                                type=\\\"date\\\"\\r\\n                                                value-format=\\\"yyyy-MM-dd\\\"\\r\\n                                                :clearable=\\\"false\\\"\\r\\n                                                format=\\\"dd-MM-yyyy\\\"\\r\\n                                                readonly\\r\\n                                                :picker-options=\\\"datEmision\\\"\\r\\n                                            >\\r\\n                                            </el-date-picker>\\r\\n                                        </div>\\r\\n                                    </div>\\r\\n                                </div>\\r\\n                                <div class=\\\"row \\\">\\r\\n                                    <div class=\\\"col-lg-6 \\\">\\r\\n                                        <div class=\\\"form-group\\\">\\r\\n                                            <template>\\r\\n                                                <div\\r\\n                                                    class=\\\"el-input el-input-group col-md-6 \\\"\\r\\n                                                    style=\\\"margin-bottom:3px;\\\"\\r\\n                                                >\\r\\n                                                    <label\\r\\n                                                        class=\\\"control-label\\\"\\r\\n                                                        style=\\\"margin-right:3px;\\\"\\r\\n                                                        >Seleccion de\\r\\n                                                        Cliente</label\\r\\n                                                    >\\r\\n                                                    <el-button\\r\\n                                                        :disabled=\\\"!value\\\"\\r\\n                                                        @click=\\\"\\r\\n                                                            showDialogNewPerson = true\\r\\n                                                        \\\"\\r\\n                                                        >Editar\\r\\n                                                        cliente</el-button\\r\\n                                                    >\\r\\n                                                    <el-button\\r\\n                                                        @click=\\\"createClient\\\"\\r\\n                                                        >Nuevo\\r\\n                                                        cliente</el-button\\r\\n                                                    >\\r\\n                                                </div>\\r\\n                                            </template>\\r\\n                                        </div>\\r\\n                                    </div>\\r\\n                                    <div class=\\\"col-12 col-sm-8 col-lg-6\\\">\\r\\n                                        <el-select\\r\\n                                            class=\\\"col-md-6\\\"\\r\\n                                            ref=\\\"select_person\\\"\\r\\n                                            v-model=\\\"value\\\"\\r\\n                                            filterable\\r\\n                                            clearable\\r\\n                                            size=\\\"small\\\"\\r\\n                                            placeholder=\\\"Cliente\\\"\\r\\n                                            :disabled=\\\"loading\\\"\\r\\n                                            @change=\\\"changeCustomer\\\"\\r\\n                                            @keyup.native=\\\"keyupCustomer\\\"\\r\\n                                            @keyup.enter.native=\\\"\\r\\n                                                keyupCustomer()\\r\\n                                            \\\"\\r\\n                                        >\\r\\n                                            <el-option\\r\\n                                                v-for=\\\"option in customers\\\"\\r\\n                                                :key=\\\"option.id\\\"\\r\\n                                                :label=\\\"option.description\\\"\\r\\n                                                :value=\\\"option.id\\\"\\r\\n                                            ></el-option>\\r\\n                                        </el-select>\\r\\n                                    </div>\\r\\n                                </div>\\r\\n                                <div class=\\\"row col-lg-6 col-xl-12\\\">\\r\\n                                    <div class=\\\"form-group\\\">\\r\\n                                        <label class=\\\"control-label\\\"\\r\\n                                            >Observaciones</label\\r\\n                                        >\\r\\n                                        <el-input\\r\\n                                            type=\\\"textarea\\\"\\r\\n                                            :rows=\\\"2\\\"\\r\\n                                            v-model=\\\"form.observation\\\"\\r\\n                                        ></el-input>\\r\\n                                    </div>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                    </div>\\r\\n\\r\\n                    <div class=\\\"col-lg-12\\\">\\r\\n                        <div class=\\\" mb-2 \\\">\\r\\n                            <div\\r\\n                                class=\\\" text-center text-dark card  bg-light  \\\"\\r\\n                            >\\r\\n                                <div class=\\\"row\\\">\\r\\n                                    <div class=\\\"  col-lg-12 \\\">\\r\\n                                        <div class=\\\" align-items-start \\\">\\r\\n                                            <label class=\\\"control-label\\\"\\r\\n                                                >Medios de Pago</label\\r\\n                                            >\\r\\n                                            <label\\r\\n                                                role=\\\"button\\\"\\r\\n                                                class=\\\"text-primary control-label\\\"\\r\\n                                            ></label>\\r\\n                                        </div>\\r\\n                                        <div\\r\\n                                            class=\\\"radio-tile-group2 flex-wrap\\\"\\r\\n                                        >\\r\\n                                            <div\\r\\n                                                class=\\\"input-container2 border rounded-sm\\\"\\r\\n                                            >\\r\\n                                                <input\\r\\n                                                    id=\\\"cash\\\"\\r\\n                                                    v-model=\\\"method_payments\\\"\\r\\n                                                    class=\\\"radio-button2\\\"\\r\\n                                                    type=\\\"radio\\\"\\r\\n                                                    name=\\\"method_payment\\\"\\r\\n                                                    value=\\\"01\\\"\\r\\n                                                    @change=\\\"\\r\\n                                                        method_payment(\\r\\n                                                            'Efectivo'\\r\\n                                                        )\\r\\n                                                    \\\"\\r\\n                                                />\\r\\n                                                <div\\r\\n                                                    class=\\\"radio-tile2\\\"\\r\\n                                                    style=\\\"background-image: url('../../images/botonEfectivo.png') ; background-size: contain ; background-repeat: no-repeat\\\"\\r\\n                                                >\\r\\n                                                    <div\\r\\n                                                        class=\\\"icon walk-icon\\\"\\r\\n                                                    ></div>\\r\\n                                                    <label\\r\\n                                                        for=\\\"cash\\\"\\r\\n                                                        class=\\\"radio-tile-label2\\\"\\r\\n                                                    ></label>\\r\\n                                                </div>\\r\\n                                            </div>\\r\\n                                            <div\\r\\n                                                class=\\\"input-container2 border rounded-sm\\\"\\r\\n                                            >\\r\\n                                                <input\\r\\n                                                    id=\\\"culqui\\\"\\r\\n                                                    v-model=\\\"method_payments\\\"\\r\\n                                                    class=\\\"radio-button2\\\"\\r\\n                                                    type=\\\"radio\\\"\\r\\n                                                    name=\\\"method_payment\\\"\\r\\n                                                    value=\\\"02\\\"\\r\\n                                                    @change=\\\"\\r\\n                                                        method_payment('Culqui')\\r\\n                                                    \\\"\\r\\n                                                />\\r\\n                                                <div\\r\\n                                                    class=\\\"radio-tile2\\\"\\r\\n                                                    style=\\\"background-image: url('../../images/CulquiIcon.png') ; background-size: contain ; background-repeat: no-repeat\\\"\\r\\n                                                >\\r\\n                                                    <div\\r\\n                                                        class=\\\"icon bike-icon\\\"\\r\\n                                                    ></div>\\r\\n                                                    <label\\r\\n                                                        for=\\\"Tarjeta\\\"\\r\\n                                                        class=\\\"radio-tile-label2\\\"\\r\\n                                                    ></label>\\r\\n                                                </div>\\r\\n                                            </div>\\r\\n                                            <div\\r\\n                                                class=\\\"input-container2 border rounded-sm\\\"\\r\\n                                            >\\r\\n                                                <input\\r\\n                                                    id=\\\"plin\\\"\\r\\n                                                    v-model=\\\"method_payments\\\"\\r\\n                                                    class=\\\"radio-button2\\\"\\r\\n                                                    type=\\\"radio\\\"\\r\\n                                                    name=\\\"method_payment\\\"\\r\\n                                                    value=\\\"05\\\"\\r\\n                                                    @change=\\\"\\r\\n                                                        method_payment(\\r\\n                                                            'TARJETA: IZYPAY'\\r\\n                                                        )\\r\\n                                                    \\\"\\r\\n                                                />\\r\\n                                                <div\\r\\n                                                    class=\\\"radio-tile2\\\"\\r\\n                                                    style=\\\"background-image: url('../../images/botonIzipay.png') ; background-size: contain ; background-repeat: no-repeat; \\\"\\r\\n                                                >\\r\\n                                                    <div\\r\\n                                                        class=\\\"icon bike-icon\\\"\\r\\n                                                    ></div>\\r\\n                                                    <label\\r\\n                                                        for=\\\"Tarjeta\\\"\\r\\n                                                        class=\\\"radio-tile-label2\\\"\\r\\n                                                    ></label>\\r\\n                                                </div>\\r\\n                                            </div>\\r\\n                                            <div\\r\\n                                                class=\\\"input-container2 border rounded-sm\\\"\\r\\n                                            >\\r\\n                                                <input\\r\\n                                                    id=\\\"plin\\\"\\r\\n                                                    v-model=\\\"method_payments\\\"\\r\\n                                                    class=\\\"radio-button2\\\"\\r\\n                                                    type=\\\"radio\\\"\\r\\n                                                    name=\\\"method_payment\\\"\\r\\n                                                    value=\\\"06\\\"\\r\\n                                                    @change=\\\"\\r\\n                                                        method_payment(\\r\\n                                                            'TARJETA: NIUBIZ'\\r\\n                                                        )\\r\\n                                                    \\\"\\r\\n                                                />\\r\\n                                                <div\\r\\n                                                    class=\\\"radio-tile2\\\"\\r\\n                                                    style=\\\"background-image: url('../../images/botonNiubiz.png') ; background-size: contain ; background-repeat: no-repeat; \\\"\\r\\n                                                >\\r\\n                                                    <div\\r\\n                                                        class=\\\"icon bike-icon\\\"\\r\\n                                                    ></div>\\r\\n                                                    <label\\r\\n                                                        for=\\\"Tarjeta\\\"\\r\\n                                                        class=\\\"radio-tile-label2\\\"\\r\\n                                                    ></label>\\r\\n                                                </div>\\r\\n                                            </div>\\r\\n                                            <div\\r\\n                                                class=\\\"input-container2 border rounded-sm\\\"\\r\\n                                            >\\r\\n                            